SELECT experiment_type, description, date, status, notes
FROM experiments
WHERE experiment_id = 0 OR experiment_id = 1;

SELECT normalization_method, Normalization_value
FROM Normalization
WHERE sample_id = 1 AND gene_id = 0;

SELECT AVG(Normalization_value) AS average_normalization_value
FROM Normalization
WHERE gene_id = 0;

SELECT normalization_method, AVG(Normalization_value) AS average_normalization
FROM Normalization
GROUP BY normalization_method;

SELECT AVG(expression_level) AS average_expression_level
FROM expression_data
WHERE gene_id = (SELECT gene_id FROM genes WHERE gene_name = 'Mdm2');
